package com.interview.incidentrca.service;
import com.interview.incidentrca.entity.*;import com.interview.incidentrca.enums.*;import org.junit.jupiter.api.Test;import java.time.Instant;import static org.assertj.core.api.Assertions.assertThat;
class SlaServiceTest{private final SlaService service=new SlaService(); @Test void criticalIncidentBreachesAfterOneHour(){var i=Incident.builder().severity(Severity.CRITICAL).createdAt(Instant.now().minusSeconds(4000)).status(IncidentStatus.OPEN).build();assertThat(service.state(i)).isEqualTo(SlaState.BREACHED);} @Test void lowIncidentStaysWithinSlaEarly(){var i=Incident.builder().severity(Severity.LOW).createdAt(Instant.now().minusSeconds(60)).status(IncidentStatus.OPEN).build();assertThat(service.state(i)).isEqualTo(SlaState.WITHIN_SLA);}}
